import { useState } from "react"

export interface HoverBtnProps {
  children?: React.ReactNode
  onClick?: (e: React.MouseEvent<HTMLButtonElement>) => void
  style?: React.CSSProperties
  title?: string
  disabled?: boolean
  accentColor?: string
  /** Rest (and hover) outline, e.g. `1px solid #fff` — Figma default variant only */
  restBorder?: string
}

export function HoverBtn({
  style,
  children,
  onClick,
  title,
  disabled,
  accentColor = "rgba(0,0,0,0.06)",
  restBorder,
}: HoverBtnProps) {
  const [hov, setHov] = useState(false)
  return (
    <button
      title={title}
      onClick={onClick}
      disabled={disabled}
      onMouseEnter={() => setHov(true)}
      onMouseLeave={() => setHov(false)}
      style={{
        ...style,
        fontFamily: '"Inter", -apple-system, BlinkMacSystemFont, sans-serif',
        fontWeight: 400,
        borderRadius: "6px",
        opacity: disabled ? 0.55 : 1,
        background: hov ? accentColor : style?.background ?? "transparent",
        ...(restBorder && !disabled ? { border: restBorder } : {}),
      }}
    >
      {children}
    </button>
  )
}
